def convex_hull_4d(points: List[Tuple[float, float, float, float]]) -> List[Tuple[float, float, float, float]]:
    """
    Calculates the minimal convex hull of the given 4-dimensional points.
    """
    if len(points) < 1:
        return []
    if len(points) == 1:
        return points

    if not is_valid_4d_points(points):
        raise ValueError("All points must be 4-dimensional")

    points = np.array(points)
    hull = ConvexHull(points)

    return [tuple(point) for point in points[hull.vertices]]

class ConvexHull:
    def __init__(self, points: np.ndarray):
        self.points = points
        self.vertices = self._calculate_hull()

    def _calculate_hull(self) -> np.ndarray:
        """
        Calculates the indices of the vertices of the convex hull.
        """
        if len(self.points) <= 3:
            return np.arange(len(self.points))

        hull = []
        for i in range(len(self.points)):
            simplex = self.points[[i, (i+1)%len(self.points), (i+2)%len(self.points), (i+3)%len(self.points)]]
            if np.linalg.matrix_rank(simplex) == 4:
                hull.append(i)

        return np.array(hull)

