class ConvexHull4D:
    def __init__(self, points):
        self.points = np.array(points)
        self.validate_points()
        self.convex_hull = self.compute_convex_hull()
        self.vertices = self.convex_hull.vertices
        self.volume = self.compute_volume()

    def validate_points(self):
        if len(self.points) < 1:
            raise ValueError("At least one point is required.")
        if self.points.shape[1] != 4:
            raise ValueError("Points must be 4-dimensional.")

    def compute_convex_hull(self):
        return ConvexHull(self.points)

    def compute_volume(self):
        simplex_volumes = []
        for simplex in self.convex_hull.simplices:
            vertices = self.points[simplex]
            volume = np.abs(np.linalg.det(vertices)) / factorial(len(vertices))
            simplex_volumes.append(volume)
        return sum(simplex_volumes)

def factorial(n):
    if n == 0 or n == 1:
        return 1
    else:
        return n * factorial(n-1)

