from typing import List, Tuple

def convex_hull_4d(points: List[Tuple[float, float, float, float]]) -> List[Tuple[float, float, float, float]]:
    """
    Compute the convex hull of a set of 4D points.

    Args:
        points (List[Tuple[float, float, float, float]]): A list of 4D points.

    Returns:
        List[Tuple[float, float, float, float]]: The vertices of the convex hull.
    """
    if len(points) < 4:
        return points

    points = np.array(points)

    # Check if all points are coplanar
    _, _, _, s = np.linalg.svd(points, full_matrices=False)
    if abs(s[-1]) < 1e-10:
        return list(points)

    hull = []
    for i in range(len(points)):
        for j in range(i+1, len(points)):
            for k in range(j+1, len(points)):
                for l in range(k+1, len(points)):
                    simplex = np.array([points[i], points[j], points[k], points[l]])
                    if np.linalg.det(simplex) != 0:
                        hull.append(tuple(points[i]))
                        hull.append(tuple(points[j]))
                        hull.append(tuple(points[k]))
                        hull.append(tuple(points[l]))

    return list(set(hull))

