    if not validate_points(points):
        raise ValueError("All points must be 4-dimensional")

    points = np.array(points)
    hull = reduce(np.union1d, (
        qhull(points[:, i:i+4]) for i in range(4)
    ))
    return [tuple(p) for p in hull]

def qhull(points: np.ndarray) -> np.ndarray:
    from scipy.spatial import ConvexHull
    hull = ConvexHull(points)
    return hull.points[hull.vertices]
